// Worker settings - all data passed from trigger
const body = $json.body || $json;
const SUPABASE_URL = body.SUPABASE_URL;
const SUPABASE_API_KEY = body.SUPABASE_API_KEY;
const userId = body.userId;
const recipient_email = body.recipient_email;
const bcc_email = body.bcc_email || '';
const book_arc_prompt = body.book_arc_prompt || '';
const book_arc_name = body.book_arc_name || '';
const chapter_arc_prompt = body.chapter_arc_prompt || '';
const chapter_arc_name = body.chapter_arc_name || '';
const story_structure_guidelines = body.story_structure_guidelines || '';
const genre_slug = body.genre_slug || '';

return [{ json: { 
  SUPABASE_URL, SUPABASE_API_KEY, userId,
  recipient_email, bcc_email, story_structure_guidelines,
  book_arc_prompt, book_arc_name, chapter_arc_prompt, chapter_arc_name,
  genre_slug
} }];

// Extract trigger data from webhook body
const body = $('webhook_trigger').first().json.body || $('webhook_trigger').first().json;
return [{ json: {
  genre_slug: body.genre_slug || '',
  project_title: body.project_title || '',
  chapter_number: body.chapter_number || '',
  brief: body.brief || '',
  outline: body.outline || '',
  research_topics: body.research_topics || '',
  user_prompt: body.user_prompt || '',
  words_per_section: body.words_per_section || '',
  user_id: body.userId || ''
} }];

// Get or create the writing project
const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' };
const userId = $('settings').first().json.userId;
const projectTitle = $('workflow_trigger').first().json.project_title;
const genreSlug = $('workflow_trigger').first().json.genre_slug;

// Try to find the project (includes outline)
let project = null;
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.' + encodeURIComponent(projectTitle) + '&user_id=eq.' + encodeURIComponent(userId) + '&limit=1',
    headers: headers
  });
  const projects = Array.isArray(resp) ? resp : [resp];
  if (projects.length > 0 && projects[0]?.id) {
    project = projects[0];
  }
} catch (e) {}

// Create project if not found
if (!project) {
  try {
    const created = await this.helpers.httpRequest({
      method: 'POST',
      url: supabaseUrl + '/rest/v1/writing_projects_v2',
      headers: { ...headers, 'Prefer': 'return=representation' },
      body: { title: projectTitle, genre_slug: genreSlug, project_type: 'book', status: 'in_progress', chapter_count: 0, user_id: userId }
    });
    project = Array.isArray(created) ? created[0] : created;
  } catch (e) {
    // Creation may have failed due to duplicate key — retry lookup before giving up
    try {
      const retry = await this.helpers.httpRequest({
        method: 'GET',
        url: supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.' + encodeURIComponent(projectTitle) + '&user_id=eq.' + encodeURIComponent(userId) + '&limit=1',
        headers: headers
      });
      const retryProjects = Array.isArray(retry) ? retry : [retry];
      project = (retryProjects.length > 0 && retryProjects[0]?.id) ? retryProjects[0] : { id: null, title: projectTitle };
    } catch (e2) {
      project = { id: null, title: projectTitle };
    }
  }
}

// Fetch story bible entries
let storyBible = [];
if (project?.id) {
  try {
    const bibleResp = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/rest/v1/story_bible_v2?project_id=eq.' + project.id + '&user_id=eq.' + encodeURIComponent(userId) + '&order=chapter_introduced,entry_type,name',
      headers: headers
    });
    storyBible = Array.isArray(bibleResp) ? bibleResp : [];
  } catch (e) {}
}

// Fetch writing samples
let samplesText = 'No writing samples available.';
try {
  const listResp = await this.helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/storage/v1/object/list/author-content',
    headers: headers,
    body: { prefix: 'writing-samples', limit: 20 }
  });
  const files = (listResp || []).filter(f => f.name && f.name !== '.gitkeep' && f.metadata?.size > 0);
  if (files.length > 0) {
    const samples = [];
    for (const file of files.slice(0, 5)) {
      try {
        const content = await this.helpers.httpRequest({
          method: 'GET',
          url: supabaseUrl + '/storage/v1/object/author-content/writing-samples/' + file.name,
          headers: { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey },
          encoding: 'utf-8',
          json: false
        });
        samples.push(typeof content === 'string' ? content : JSON.stringify(content));
      } catch (e) {}
    }
    if (samples.length > 0) samplesText = samples.join('\n\n');
  }
} catch (e) {}

return [{ json: { project: project, story_bible: storyBible, writing_samples: samplesText, outline: project?.outline || null } }];

const trigger = $('workflow_trigger').first().json;
const genre = $('get_genre_config').first().json;
const genreData = Array.isArray(genre) ? genre[0] : genre;
const research = $('research_topic').first().json.message || '';
const projectData = $('get_project_data').first().json;
const storyBible = projectData.story_bible || [];
const writingSamples = projectData.writing_samples || '';
const bookArcPrompt = $('settings').first().json.book_arc_prompt || '';
const bookArcName = $('settings').first().json.book_arc_name || '';
const chapterArcPrompt = $('settings').first().json.chapter_arc_prompt || '';
const chapterArcName = $('settings').first().json.chapter_arc_name || '';

const wordsPerSection = parseInt(trigger.words_per_section) || 1200;
const storedOutline = projectData.outline;
let outlineText = trigger.outline || '';

if (!outlineText && storedOutline) {
  if (typeof storedOutline === 'object') {
    const parts = [];
    if (storedOutline.premise) parts.push('PREMISE: ' + storedOutline.premise);
    if (storedOutline.themes) parts.push('THEMES: ' + storedOutline.themes.join(', '));
    if (storedOutline.characters) {
      parts.push('CHARACTERS:\n' + storedOutline.characters.map(c => 
        '- ' + c.name + ' (' + c.role + '): ' + c.arc + (c.description ? ' — ' + c.description : '')
      ).join('\n'));
    }
    if (storedOutline.chapters) {
      parts.push('CHAPTER OUTLINE:\n' + storedOutline.chapters.map(ch => 
        'Ch ' + ch.number + ' — ' + ch.title + ': ' + ch.brief + (ch.arc_notes ? ' [Arc: ' + ch.arc_notes + ']' : '')
      ).join('\n'));
    }
    outlineText = parts.join('\n\n');
  } else {
    outlineText = String(storedOutline);
  }
}

const bibleText = storyBible.length > 0
  ? storyBible.map(e => '[' + e.entry_type + '] ' + e.name + ': ' + e.description + ' (ch' + e.chapter_introduced + ')').join('\n')
  : 'No story bible entries yet.';

const rawChapter = (trigger.chapter_number || '').toString().trim();
const isPrologue = /^(prologue|prol|0)$/i.test(rawChapter);
const isEpilogue = /^(epilogue|epil)$/i.test(rawChapter);
const chapterNum = isPrologue ? 0 : (isEpilogue ? -1 : parseInt(rawChapter));
const chapterLabel = isPrologue ? 'Prologue' : (isEpilogue ? 'Epilogue' : 'Chapter ' + chapterNum);

let chapterBrief = trigger.brief || '';
let chapterOutlineText = '';
let subChapters = [];
let chapterOutlineMeta = {};

if (storedOutline && storedOutline.chapters) {
  let thisChapter;
  if (isPrologue) {
    thisChapter = storedOutline.chapters.find(ch => ch.number === 0 || /^prologue$/i.test(String(ch.title)));
  } else if (isEpilogue) {
    thisChapter = storedOutline.chapters.find(ch => /^epilogue$/i.test(String(ch.title)) || ch.number > storedOutline.chapters.filter(c => typeof c.number === 'number').length);
  } else {
    thisChapter = storedOutline.chapters.find(ch => ch.number === chapterNum);
  }
  if (thisChapter) {
    if (!trigger.brief) chapterBrief = thisChapter.brief + (thisChapter.arc_notes ? '\nArc notes: ' + thisChapter.arc_notes : '');
    if (thisChapter.research_topics) {
      // research topics available
    }
  }
  if (thisChapter && thisChapter.chapter_outline && thisChapter.chapter_outline.sub_chapters && thisChapter.chapter_outline.sub_chapters.length > 0) {
    const co = thisChapter.chapter_outline;
    subChapters = co.sub_chapters;
    chapterOutlineMeta = co;
  }
}

// SAFETY GATE
if (subChapters.length === 0) {
  throw new Error('Cannot write ' + chapterLabel + ' — no chapter outline with sub-chapters found. Create one first: "create a chapter outline for ' + chapterLabel.toLowerCase() + ' of ' + trigger.project_title + '"');
}

// Fill in story arc placeholders with actual project data
const protagonist = (storedOutline && storedOutline.characters) ? storedOutline.characters.find(c => c.role === 'Protagonist') : null;
const protagonistDesc = protagonist ? protagonist.name + ' — ' + protagonist.arc : 'See characters in book outline';

function fillArcPlaceholders(arcText) {
  if (!arcText) return '';
  return arcText
    .replace(/\[a full book \/ a single chapter[^\]]*\]/gi, 'a single sub-chapter scene')
    .replace(/\[Book \/ Chapter \/ Short Story[^\]]*\]/gi, 'Sub-chapter scene within a novel chapter')
    .replace(/\[e\.g\., thriller[^\]]*\]/gi, (genreData && genreData.genre_name) || 'fiction')
    .replace(/\[Describe briefly[^\]]*\]/gi, protagonistDesc)
    .replace(/\[What is the core problem[^\]]*\]/gi, (storedOutline && storedOutline.premise) || 'See book outline premise')
    .replace(/\[Where and when[^\]]*\]/gi, 'See sub-chapter setting below')
    .replace(/\[What does the protagonist stand to lose[^\]]*\]/gi, 'See book outline and chapter arc notes')
    .replace(/\[e\.g\., 1,000 words[^\]]*\]/gi, wordsPerSection.toLocaleString() + ' words per sub-chapter')
    .replace(/\[.*?central moral.*?\]/gi, 'See book outline themes')
    .replace(/\[.*?Genre.*?\]/gi, (genreData && genreData.genre_name) || 'fiction')
    .replace(/\[.*?Main character.*?\]/gi, protagonistDesc)
    .replace(/\[.*?Setting.*?\]/gi, 'See sub-chapter setting')
    .replace(/\[.*?Length goal.*?\]/gi, wordsPerSection.toLocaleString() + ' words');
}

const filledChapterArc = fillArcPlaceholders(chapterArcPrompt);
const filledBookArc = fillArcPlaceholders(bookArcPrompt);

// ============================================================
// SPLIT PROMPT: system_prompt (cached) + user_prompt (variable)
// The agent systemMessage receives the stable content — Anthropic
// auto-caches it across all sub-chapter iterations and tool rounds.
// The agent text (user message) gets the per-sub-chapter assignment.
// ============================================================

// SYSTEM PROMPT (identical across all sub-chapters — CACHED)
const allSubChaptersList = subChapters.map(sc =>
  'Sub-chapter ' + sc.number + ' — ' + sc.title + ': ' + sc.brief
).join('\\n');

const chapterArc = chapterOutlineMeta.chapter_story_arc || chapterArcName || bookArcName || 'Not specified';
const systemPrompt =
  'You are a world-class novelist writing the ' + chapterLabel + ' of "' + trigger.project_title + '", a ' + (genreData && genreData.genre_name || 'fiction') + ' novel.\n\n' +
  '## ⚠️ MANDATORY STORY ARC: ' + chapterArc + '\n' +
  'This chapter uses the ' + chapterArc + ' structure. Every sub-chapter MUST execute its assigned arc beat exactly. This is the #1 priority — it OVERRIDES pacing preferences, tone defaults, and writing style when they conflict.\n' +
  (chapterArc === 'Fichtean Curve' ? '- Fichtean Curve REQUIRES: Open IN MEDIAS RES (mid-action, immediate tension). Build through THREE ESCALATING CRISES. Each crisis more intense than the last. Short, impactful resolution. NO slow setup. NO contemplative openings. NO gentle pacing. Backstory revealed ON THE MOVE during action, never in exposition blocks.\n' : '') +
  (chapterArc === 'Three-Act Structure' ? '- Three-Act Structure REQUIRES: Act I setup with inciting incident, Act II rising action with complications, Act III climax and resolution.\n' : '') +
  'If an arc beat says "Opening in Medias Res" — your FIRST SENTENCE must drop the reader into action. If it says "Crisis" — escalate conflict dramatically. If it says "Climax" — deliver maximum tension.\n\n' +
  '## Genre: ' + (genreData && genreData.genre_name || 'fiction') +
  '\n\n## Writing Style\nClear, everyday language. Short sentences. No cliches. Show, don\'t tell. Concrete details, sensory moments. Short paragraphs. Respect the reader.\n\n' +
  '## SCENE REQUIREMENTS\n- CHARACTER DESCRIPTIONS: Only provide a full physical description (age, build, face, clothing) on a character\'s FIRST APPEARANCE IN THE ENTIRE BOOK. Use the character\'s first_described_in field from the outline to know if they have already been introduced. If they were described in a previous chapter, reference them naturally without repeating their physical description. Use EXACT age and appearance from the book outline — never invent or change these details.\n- CHARACTER NAMES: Use the exact name_format from the book outline. Be consistent throughout.\n- Every scene: LOCAL COLOR (sounds, smells, textures, light, weather).\n- Each sub-chapter is a DISTINCT SCENE with clear beginning, middle, end. Must feel like a chapter break before and after.\n- Do NOT blend sub-chapters into continuous narrative. Each sub-chapter stands alone.\n\n' +
  '## CHARACTER NAME RULES — MANDATORY\nThe following name formats are LOCKED. Use ONLY these forms when referring to characters:\n' + (storedOutline && storedOutline.characters ? storedOutline.characters.filter(c => c.name_format).map(c => '- ' + c.name + ': ' + c.name_format).join('\\n') : '') + '\nIf a character has no name_format specified, use their full name from the outline. NEVER abbreviate or create name forms not listed above. UNIVERSAL RULE: Never combine an honorific (Dr., Mr., Mrs., Prof.) with only a first name — use honorific + last name (Dr. Moyaone) or first name alone (Tayak), never honorific + first name (Dr. Tayak).\n\n## RETRIEVING CONTEXT\nUse the search_project_knowledge tool to retrieve character details, story bible, genre guidelines, chapter structure, and research facts.\nDo NOT invent characters or details. Make ONE search call.';

// Output one item per sub-chapter
// Load Q/A feedback from previous write if available
let thisChapterQA = '';
if (chapterOutlineMeta && storedOutline && storedOutline.chapters) {
  const rawCh2 = (trigger.chapter_number || '').toString().trim();
  const chNum2 = /^(prologue|prol|0)$/i.test(rawCh2) ? 0 : (/^(epilogue|epil)$/i.test(rawCh2) ? -1 : parseInt(rawCh2));
  const thisCh2 = storedOutline.chapters.find(ch => ch.number === chNum2);
  if (thisCh2 && thisCh2.last_qa_report && thisCh2.last_qa_report.concerns && thisCh2.last_qa_report.concerns.length > 0) {
    thisChapterQA = thisCh2.last_qa_report.concerns.map((c, i) => (i+1) + '. ' + c).join('\\n');
  }
}

const items = subChapters.map((sc, index) => {
  const prevSc = index > 0 ? subChapters[index - 1] : null;
  const prevSummaries = prevSc ? 'Previous sub-chapter ' + prevSc.number + ' (' + prevSc.title + '): ' + prevSc.brief : '';

  // nextSc removed — not needed

  // USER PROMPT (changes per sub-chapter — NOT cached)
  const userPrompt =
    'Write Sub-chapter ' + sc.number + ' of ' + subChapters.length + ': ' + sc.title + '\n' +
    'Begin with the sub-chapter title as a heading on its own line (e.g., "The Committee Room"), then write narrative prose. No JSON, no metadata, no numbering.\n\n' +
    'Arc Beat (' + (chapterOutlineMeta.chapter_story_arc || '') + '): ' + (sc.arc_beat || '') + '\n' +
    'Characters: ' + (sc.characters || []).join(', ') + '\n' +
    'Setting: ' + (sc.setting || '') + '\n' +
    'Emotional Tone: ' + (sc.emotional_tone || '') + '\n' +
    '\n## MANDATORY SCENE BRIEF — YOU MUST WRITE EXACTLY THIS:\n' + (sc.brief || '') + '\n\nThe above brief is your SCRIPT. Every event, action, and detail described in the brief MUST appear in your prose. Do NOT substitute different events. Do NOT skip any element. Do NOT reinterpret the brief — dramatize it exactly as written.\n' +
    'Book Arc Connection: ' + (sc.connects_to_book_arc || '') + '\n\n' +
    'RULES:\n' +
    '- Write approximately ' + wordsPerSection.toLocaleString() + ' words\n' +
    '- Use ONLY the characters listed above\n' +
    '- This sub-chapter MUST execute its arc beat: ' + (sc.arc_beat || '') + '. This is not a suggestion — structure your prose around this beat. If the beat says "Opening in Medias Res" start mid-action with immediate tension. If it says "Crisis" escalate conflict dramatically. If it says "Climax" deliver the highest tension. If it says "Resolution" close with impact.\n' +
    '- Match the emotional tone: ' + (sc.emotional_tone || '') + '\n' +
    '- This sub-chapter must be a DISTINCT SCENE with a clear beginning, middle, and end. It should feel like a chapter break before and after.\n' +
    (index === 0 ? '- OPENING sub-chapter: establish the scene, full character description, set the tone. If the arc is Fichtean Curve, open IN MEDIAS RES — drop the reader into action, not setup.\n' : '') +
    (index === subChapters.length - 1 ? '- FINAL sub-chapter: provide closure, create a hook for next chapter\n' : '') +
    (prevSummaries ? '\nPrevious sub-chapter (maintain continuity):\n' + prevSummaries + '\n' : '') +

    '\n' +
    (thisChapterQA ? '\nQ/A FEEDBACK FROM PREVIOUS WRITE — YOU MUST ADDRESS THESE ISSUES:\n' + thisChapterQA + '\n' : '') +
    (trigger.user_prompt ? '\n## SPECIAL INSTRUCTIONS FROM USER\n' + trigger.user_prompt + '\nYou MUST incorporate these instructions into your writing. They override default descriptions and details from the outline.\n\n' : '') +
    (trigger.brief && !trigger.user_prompt ? '\n## SPECIAL INSTRUCTIONS FROM USER\n' + trigger.brief + '\nYou MUST incorporate these instructions into your writing. They override default descriptions and details from the outline.\n\n' : '') +
    'STEPS: 1) Make exactly ONE call to search_project_knowledge with a query combining character names, story bible, and genre guidelines. 2) Then immediately write the full sub-chapter prose. Do NOT make a second tool call.';

  return {
    json: {
      system_prompt: systemPrompt,
      user_prompt: userPrompt,
      sub_chapter_number: sc.number,
      sub_chapter_title: sc.title,
      sub_chapter_characters: (sc.characters || []).join(', '),
      words_per_section: wordsPerSection,
      project_id: projectData.project && projectData.project.id,
      total_sub_chapters: subChapters.length,
      chapter_label: chapterLabel,
      chapter_outline_meta: chapterOutlineMeta
    }
  };
});

return items;

// Check for failed sub-chapters
const allItems = $input.all();
const totalExpected = allItems[0]?.json?.total_sub_chapters || 0;
const successItems = allItems.filter(item => item.json?.output && item.json.output.length > 100);
const failedCount = totalExpected - successItems.length;

const items = $input.all();
const firstItem = $('build_sub_chapter_prompts').first().json;
const chapterLabel = firstItem.chapter_label || 'Chapter';
const meta = firstItem.chapter_outline_meta || {};

// Collect all sub-chapter texts
const subChapterTexts = items.map((item, i) => {
  const text = item.json.output || item.json.text || item.json.response || '';
  return text;
});

// Concatenate with scene breaks
const fullText = subChapterTexts.join('\n\n---\n\n');
const wordCount = fullText.split(/\s+/).length;

// Build chapter summary from meta
const summary = meta.chapter_summary || 'Chapter written with ' + items.length + ' sub-chapters.';

return [{ json: {
  output: {
    chapter_title: meta.chapter_title || chapterLabel,
    chapter_text: fullText,
    word_count: wordCount,
    chapter_summary: summary,
    next_chapter_notes: 'Continue to the next chapter per the book outline.',
    new_story_bible_entries: []
  }
} }];

// Update story bible with new entries from this chapter
const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' };
const userId = $('settings').first().json.userId;
const projectId = $('build_sub_chapter_prompts').first().json.project_id;
const rawCh = ($('workflow_trigger').first().json.chapter_number || '').toString().trim();
const isProl = /^(prologue|prol|0)$/i.test(rawCh);
const isEpil = /^(epilogue|epil)$/i.test(rawCh);
const chapterNum = isProl ? 0 : (isEpil ? 999 : (parseInt(rawCh) || 0));
const chapterLabel = isProl ? 'Prologue' : (isEpil ? 'Epilogue' : rawCh);
const output = $input.first().json.output || {};
const newEntries = output.new_story_bible_entries || [];

// Insert new story bible entries
if (newEntries.length > 0 && projectId) {
  try {
    const entries = newEntries.map(e => ({
      entry_type: e.entry_type,
      name: e.name,
      description: e.description,
      project_id: projectId,
      chapter_introduced: chapterNum,
      last_chapter_seen: chapterNum,
      user_id: userId
    }));
    await this.helpers.httpRequest({
      method: 'POST',
      url: supabaseUrl + '/rest/v1/story_bible_v2',
      headers: headers,
      body: entries
    });
  } catch (e) {}
}

// Update project chapter count
if (projectId) {
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: supabaseUrl + '/rest/v1/writing_projects_v2?id=eq.' + projectId + '&user_id=eq.' + encodeURIComponent(userId),
      headers: headers,
      body: Object.assign({ status: 'in_progress', updated_at: new Date().toISOString() }, (!isProl && !isEpil) ? { chapter_count: chapterNum } : {})
    });
  } catch (e) {}
}

return [{ json: { output: output, project_id: projectId } }];

