  (chapterArc === 'Three-Act Structure' ? '- Three-Act Structure REQUIRES: Act I setup with inciting incident, Act II rising action with complications, Act III climax and resolution.\n' : '') +
  'If an arc beat says "Opening in Medias Res" — your FIRST SENTENCE must drop the reader into action. If it says "Crisis" — escalate conflict dramatically. If it says "Climax" — deliver maximum tension.\n\n' +
  '## Genre: ' + (genreData && genreData.genre_name || 'fiction') +
  '\n\n## Writing Style\nClear, everyday language. Short sentences. No cliches. Show, don\'t tell. Concrete details, sensory moments. Short paragraphs. Respect the reader.\n\n' +
  '## SCENE REQUIREMENTS\n- CHARACTER DESCRIPTIONS: Only provide a full physical description (age, build, face, clothing) on a character\'s FIRST APPEARANCE IN THE ENTIRE BOOK. Use the character\'s first_described_in field from the outline to know if they have already been introduced. If they were described in a previous chapter, reference them naturally without repeating their physical description. Use EXACT age and appearance from the book outline — never invent or change these details.\n- CHARACTER NAMES: Use the exact name_format from the book outline. Be consistent throughout.\n- Every scene: LOCAL COLOR (sounds, smells, textures, light, weather).\n- Each sub-chapter is a DISTINCT SCENE with clear beginning, middle, end. Must feel like a chapter break before and after.\n- Do NOT blend sub-chapters into continuous narrative. Each sub-chapter stands alone.\n\n' +
  '## CHARACTER NAME RULES — MANDATORY\nThe following name formats are LOCKED. Use ONLY these forms when referring to characters:\n' + (storedOutline && storedOutline.characters ? storedOutline.characters.filter(c => c.name_format).map(c => '- ' + c.name + ': ' + c.name_format).join('\\n') : '') + '\nIf a character has no name_format specified, use their full name from the outline. NEVER abbreviate or create name forms not listed above. UNIVERSAL RULE: Never combine an honorific (Dr., Mr., Mrs., Prof.) with only a first name — use honorific + last name (Dr. Moyaone) or first name alone (Tayak), never honorific + first name (Dr. Tayak).\n\n## RETRIEVING CONTEXT\nUse the search_project_knowledge tool to retrieve character details, story bible, genre guidelines, chapter structure, and research facts.\nDo NOT invent characters or details. Make ONE search call.';

// Output one item per sub-chapter
// Load Q/A feedback from previous write if available
let thisChapterQA = '';
if (chapterOutlineMeta && storedOutline && storedOutline.chapters) {
  const rawCh2 = (trigger.chapter_number || '').toString().trim();
  const chNum2 = /^(prologue|prol|0)$/i.test(rawCh2) ? 0 : (/^(epilogue|epil)$/i.test(rawCh2) ? -1 : parseInt(rawCh2));
  const thisCh2 = storedOutline.chapters.find(ch => ch.number === chNum2);
  if (thisCh2 && thisCh2.last_qa_report && thisCh2.last_qa_report.concerns && thisCh2.last_qa_report.concerns.length > 0) {
    thisChapterQA = thisCh2.last_qa_report.concerns.map((c, i) => (i+1) + '. ' + c).join('\\n');
  }
}

const items = subChapters.map((sc, index) => {
  const prevSc = index > 0 ? subChapters[index - 1] : null;
  const prevSummaries = prevSc ? 'Previous sub-chapter ' + prevSc.number + ' (' + prevSc.title + '): ' + prevSc.brief : '';

  // nextSc removed — not needed

  // USER PROMPT (changes per sub-chapter — NOT cached)
  const userPrompt =
    'Write Sub-chapter ' + sc.number + ' of ' + subChapters.length + ': ' + sc.title + '\n' +
    'Begin with the sub-chapter title as a heading on its own line (e.g., "The Committee Room"), then write narrative prose. No JSON, no metadata, no numbering.\n\n' +
    'Arc Beat (' + (chapterOutlineMeta.chapter_story_arc || '') + '): ' + (sc.arc_beat || '') + '\n' +
    'Characters: ' + (sc.characters || []).join(', ') + '\n' +
    'Setting: ' + (sc.setting || '') + '\n' +
    'Emotional Tone: ' + (sc.emotional_tone || '') + '\n' +
    '\n## MANDATORY SCENE BRIEF — YOU MUST WRITE EXACTLY THIS:\n' + (sc.brief || '') + '\n\nThe above brief is your SCRIPT. Every event, action, and detail described in the brief MUST appear in your prose. Do NOT substitute different events. Do NOT skip any element. Do NOT reinterpret the brief — dramatize it exactly as written.\n' +
    'Book Arc Connection: ' + (sc.connects_to_book_arc || '') + '\n\n' +
    'RULES:\n' +
    '- Write approximately ' + wordsPerSection.toLocaleString() + ' words\n' +
    '- Use ONLY the characters listed above\n' +
    '- This sub-chapter MUST execute its arc beat: ' + (sc.arc_beat || '') + '. This is not a suggestion — structure your prose around this beat. If the beat says "Opening in Medias Res" start mid-action with immediate tension. If it says "Crisis" escalate conflict dramatically. If it says "Climax" deliver the highest tension. If it says "Resolution" close with impact.\n' +
    '- Match the emotional tone: ' + (sc.emotional_tone || '') + '\n' +
    '- This sub-chapter must be a DISTINCT SCENE with a clear beginning, middle, and end. It should feel like a chapter break before and after.\n' +
    (index === 0 ? '- OPENING sub-chapter: establish the scene, full character description, set the tone. If the arc is Fichtean Curve, open IN MEDIAS RES — drop the reader into action, not setup.\n' : '') +
    (index === subChapters.length - 1 ? '- FINAL sub-chapter: provide closure, create a hook for next chapter\n' : '') +
    (prevSummaries ? '\nPrevious sub-chapter (maintain continuity):\n' + prevSummaries + '\n' : '') +

    '\n' +
    (thisChapterQA ? '\nQ/A FEEDBACK FROM PREVIOUS WRITE — YOU MUST ADDRESS THESE ISSUES:\n' + thisChapterQA + '\n' : '') +
    (trigger.user_prompt ? '\n## SPECIAL INSTRUCTIONS FROM USER\n' + trigger.user_prompt + '\nYou MUST incorporate these instructions into your writing. They override default descriptions and details from the outline.\n\n' : '') +
    (trigger.brief && !trigger.user_prompt ? '\n## SPECIAL INSTRUCTIONS FROM USER\n' + trigger.brief + '\nYou MUST incorporate these instructions into your writing. They override default descriptions and details from the outline.\n\n' : '') +
    'STEPS: 1) Make exactly ONE call to search_project_knowledge with a query combining character names, story bible, and genre guidelines. 2) Then immediately write the full sub-chapter prose. Do NOT make a second tool call.';

  return {
    json: {
      system_prompt: systemPrompt,
      user_prompt: userPrompt,
      sub_chapter_number: sc.number,
      sub_chapter_title: sc.title,
      sub_chapter_characters: (sc.characters || []).join(', '),
      words_per_section: wordsPerSection,
      project_id: projectData.project && projectData.project.id,
      total_sub_chapters: subChapters.length,
      chapter_label: chapterLabel,
      chapter_outline_meta: chapterOutlineMeta
    }
  };
});

return items;

// Check for failed sub-chapters
const allItems = $input.all();
const totalExpected = allItems[0]?.json?.total_sub_chapters || 0;
const successItems = allItems.filter(item => item.json?.output && item.json.output.length > 100);
const failedCount = totalExpected - successItems.length;

const items = $input.all();
const firstItem = $('build_sub_chapter_prompts').first().json;
const chapterLabel = firstItem.chapter_label || 'Chapter';
const meta = firstItem.chapter_outline_meta || {};

// Collect all sub-chapter texts
const subChapterTexts = items.map((item, i) => {
  const text = item.json.output || item.json.text || item.json.response || '';
  return text;
});

// Concatenate with scene breaks
const fullText = subChapterTexts.join('\n\n---\n\n');
const wordCount = fullText.split(/\s+/).length;

// Build chapter summary from meta
const summary = meta.chapter_summary || 'Chapter written with ' + items.length + ' sub-chapters.';

return [{ json: {
  output: {
    chapter_title: meta.chapter_title || chapterLabel,
    chapter_text: fullText,
    word_count: wordCount,
    chapter_summary: summary,
    next_chapter_notes: 'Continue to the next chapter per the book outline.',
    new_story_bible_entries: []
  }
} }];

// Update story bible with new entries from this chapter
const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' };
const userId = $('settings').first().json.userId;
