const rawCh = ($('workflow_trigger').first().json.chapter_number || '').toString().trim();
const isProl = /^(prologue|prol|0)$/i.test(rawCh);
const isEpil = /^(epilogue|epil)$/i.test(rawCh);
const chapterNum = isProl ? 0 : (isEpil ? 999 : (parseInt(rawCh) || 0));
const chapterLabel = isProl ? 'Prologue' : (isEpil ? 'Epilogue' : rawCh);
const output = $input.first().json.output || {};
const newEntries = output.new_story_bible_entries || [];

// Insert new story bible entries
if (newEntries.length > 0 && projectId) {
  try {
    const entries = newEntries.map(e => ({
      entry_type: e.entry_type,
      name: e.name,
      description: e.description,
      project_id: projectId,
      chapter_introduced: chapterNum,
